const express = require('express'); // Importing Express framework for handling requests & responses in node js  
var multer  = require('multer')();    // Multer is a Node.js middleware to handle `multipart/form-data`, the library handles uploads with `<input type="file">` tags 
const fs = require("fs");             // Importing File System module for handling file operations in node js  
var path    = require('path');         // Node.js builtin 'Path' object is used to manipulate filesystem paths, here we use it as a helper function of multer middleware 
const app = express();                // Initialize Express App   
app.use(multer.array());             // Middle ware for handling array-type `<input type="file">` data  
var uploadDir =  __dirname + '/uploads/';// Define the directory where we want to save uploaded files 
if (!fs.existsSync(uploadDir)){       // Check if 'Upload Directory' exists, otherwise create it using fs module   
     fs.mkdirSync(uploadDir);         
}  
app.post('/file-upload', (req, res) => {      // Define a POST route for handling file uploads 
        req.files.forEach((element)=>{           // Loop through all the files in request object   
            var filename = element.name;          // Get name of each uploaded File  
             fs.createReadStream(element.path).pipe(fs.createWriteStream(__dirname + '/uploads/'+filename));  /* Create a read stream for file and write it to the server */   
        });                                       
         res.send('Files Uploaded Successfully'); // Send response back if files are uploaded successfully  
});                                                 
app.listen(3001, () => {                            // Start Express Server on port 3001 for testing purposes                                 
     console.log("Server started at http://localhost:3001");   
 });